#include <stdio.h>

int main() {
    // Open in Write mode to create/overwrite the file
    FILE *file = fopen("save_data.txt", "w");

    if (file != NULL) {
        int finalScore = 9500;

        // Write to the file just like replacing printf
        fprintf(file, "Player Name: Hero\n");
        fprintf(file, "Final Score: %d\n", finalScore);

        fprintf(stdout, "Save Complete!\n");

        fclose(file); // Don't forget!
    }
    return 0;
}
